import{c as s,Q as a,j as n,m as e}from"./chunks/framework.Bhbi9jCp.js";const g=JSON.parse('{"title":"eBPF","description":"","frontmatter":{},"headers":[],"relativePath":"osLearning/27-eBPF.md","filePath":"osLearning/27-eBPF.md","lastUpdated":1781095972000}'),p={name:"osLearning/27-eBPF.md"};function r(i,t,o,l,d,c){return a(),n("div",null,[...t[0]||(t[0]=[e(`<h1 id="ebpf" tabindex="-1">eBPF <a class="header-anchor" href="#ebpf" aria-label="Permalink to &quot;eBPF&quot;">​</a></h1><p>想象一个排障的死局:线上某个服务偶发慢几百毫秒,日志里什么都没有(出问题的代码路径没打日志),strace 不敢挂(上一篇说过,高 QPS 服务挂 ptrace 等于自造故障),改代码加日志要发版、要重启、要等下一次复现——而问题在内核里:可能是磁盘 IO 长尾,可能是调度排队,可能是 TCP 重传。<strong>应用层工具到这里全部失明</strong>。eBPF 解的就是这个局:<strong>不改内核、不写内核模块、不重启任何东西,把一段自己写的小程序挂到内核事件点上,事件发生时就地执行、就地统计</strong>。听起来像&quot;往内核里注入代码&quot;一样危险,但它恰恰建立在一个极其严格的安全机制上——这是本篇真正的主角。</p><blockquote><p>一句话先记住:<strong>eBPF = 经过验证器(verifier)数学级审查的小程序,挂在内核事件点上运行,用 map 和用户态交换数据</strong>。verifier 保证它崩不了内核,hook 决定它挂在哪,map 负责把结果带出来。<strong>可观测性、网络、安全是它的三大主战场</strong>——它把 Linux 内核从黑盒变成了可编程平台。</p></blockquote><hr><h2 id="一、为什么需要-ebpf-四条老路都不通" tabindex="-1">一、为什么需要 eBPF:四条老路都不通 <a class="header-anchor" href="#一、为什么需要-ebpf-四条老路都不通" aria-label="Permalink to &quot;一、为什么需要 eBPF:四条老路都不通&quot;">​</a></h2><p>&quot;看内核正在发生什么&quot;这个需求一直存在,eBPF 之前有四条路,各有致命伤:</p><table tabindex="0"><thead><tr><th>老办法</th><th>致命伤</th></tr></thead><tbody><tr><td>改代码加日志</td><td>要发版重启;而且<strong>内核里的事(调度/IO/网络栈)应用代码根本看不见</strong></td></tr><tr><td>strace</td><td>ptrace 开销巨大,高 QPS 服务挂上去性能掉几倍到几十倍</td></tr><tr><td>写内核模块</td><td>跑在内核态毫无防护,一个空指针 = 整机 panic,没人敢往生产装</td></tr><tr><td>tcpdump</td><td>只能看包,看不到&quot;哪个进程、哪个函数、哪把锁&quot;和包的关联</td></tr></tbody></table><p>eBPF 的工作模式把这四个痛点全部绕开:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>写一个小程序(几十行)</span></span>
<span class="line"><span>  → 加载到内核的某个 hook 点</span></span>
<span class="line"><span>  → 对应事件每次发生,程序就地执行(纳秒级)</span></span>
<span class="line"><span>  → 统计结果写进 map(内核里的共享数据结构)</span></span>
<span class="line"><span>  → 用户态随时读 map 拿结果</span></span></code></pre></div><p>不改业务代码、不重启服务、开销低到敢常驻生产——<strong>&quot;低成本看到内核真相&quot;是 eBPF 的全部卖点</strong>。</p><hr><h2 id="二、凭什么敢往内核里塞代码-verifier" tabindex="-1">二、凭什么敢往内核里塞代码:verifier <a class="header-anchor" href="#二、凭什么敢往内核里塞代码-verifier" aria-label="Permalink to &quot;二、凭什么敢往内核里塞代码:verifier&quot;">​</a></h2><p>这是 eBPF 设计里最精彩的部分。内核模块的教训摆在那:内核态代码出错就是整机崩溃。eBPF 敢开放&quot;任何人写代码进内核&quot;,靠的是加载时的强制安检——<strong>verifier 会模拟执行你程序的所有可能路径,任何一条路径有出格的可能,直接拒绝加载</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你写 C 程序 / bpftrace 脚本</span></span>
<span class="line"><span>      │ clang -target bpf 编译</span></span>
<span class="line"><span>      ▼</span></span>
<span class="line"><span>  BPF 字节码</span></span>
<span class="line"><span>      │ bpf() syscall 申请加载</span></span>
<span class="line"><span>      ▼</span></span>
<span class="line"><span>┌── Verifier 静态审查(模拟执行所有分支)─────────────┐</span></span>
<span class="line"><span>│  ✓ 程序必然终止?(不允许无界循环,不允许死循环)      │</span></span>
<span class="line"><span>│  ✓ 所有内存访问都在边界内?                          │</span></span>
<span class="line"><span>│  ✓ 内核指针解引用前都判过空、过了 helper 校验?        │</span></span>
<span class="line"><span>│  ✓ 栈用量 ≤ 512 字节?                              │</span></span>
<span class="line"><span>│  ✓ 只调用了白名单里的 helper 函数?                   │</span></span>
<span class="line"><span>│  任何一条不满足 ──────────────→ 拒绝加载,完事        │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────┘</span></span>
<span class="line"><span>      │ 全部通过</span></span>
<span class="line"><span>      ▼</span></span>
<span class="line"><span>  JIT 编译成本机指令(跑起来几乎是原生速度)</span></span>
<span class="line"><span>      │</span></span>
<span class="line"><span>      ▼</span></span>
<span class="line"><span>  attach 到 hook 点,开始工作:</span></span>
<span class="line"><span>      内核事件发生 → 执行 BPF 程序 → 读写 map</span></span>
<span class="line"><span>                                       ↑</span></span>
<span class="line"><span>      用户态进程 ──── 读 map / ring buffer 取结果</span></span></code></pre></div><p>关键的认知转换:<strong>eBPF 程序不是&quot;被信任才能跑&quot;,是&quot;被证明无害才能跑&quot;</strong>。verifier 不看你是谁,只看程序在数学上是否不可能越界、不可能死循环、不可能解引用野指针。代价是表达能力受限——你写不了任意复杂的逻辑(循环必须有界、栈只有 512 字节),但换来的是<strong>内核敢让你上车</strong>。这笔交易就是 eBPF 整个生态的地基。</p><p>map 是另一半拼图:BPF 程序跑在内核、生命短暂(一个事件一次执行),<strong>状态和结果都存在 map 里</strong>——哈希表、数组、直方图、ring buffer,内核态写、用户态读,两个世界靠它对话。</p><hr><h2 id="三、hook-点地图-挂在哪-决定你能看见什么" tabindex="-1">三、hook 点地图:挂在哪,决定你能看见什么 <a class="header-anchor" href="#三、hook-点地图-挂在哪-决定你能看见什么" aria-label="Permalink to &quot;三、hook 点地图:挂在哪,决定你能看见什么&quot;">​</a></h2><p>eBPF 程序本身只是&quot;一段会被执行的逻辑&quot;,真正决定它用途的是 attach 到哪个 hook:</p><table tabindex="0"><thead><tr><th>Hook</th><th>挂在哪</th><th>典型用途</th></tr></thead><tbody><tr><td>tracepoint</td><td>内核预埋的稳定跟踪点</td><td>看 syscall、调度、IO 事件(<strong>首选</strong>)</td></tr><tr><td>kprobe / kretprobe</td><td>几乎任意内核函数的入口/返回</td><td>tracepoint 没覆盖时的万能后门</td></tr><tr><td>uprobe / uretprobe</td><td><strong>用户态</strong>程序的函数</td><td>看 SSL 加密前的明文、malloc 调用</td></tr><tr><td>perf event</td><td>CPU 性能计数器 / 定时采样</td><td>CPU profiling(26 篇 perf 的底层)</td></tr><tr><td>XDP</td><td>网卡驱动收包的最早一刻</td><td>DDoS 防御、负载均衡(第六节)</td></tr><tr><td>TC</td><td>流量控制层(协议栈内)</td><td>容器网络策略、限速</td></tr><tr><td>cgroup hooks</td><td>按 cgroup 挂网络/syscall 钩子</td><td>容器粒度的过滤和观测</td></tr><tr><td>LSM</td><td>安全模块挂点</td><td>运行时安全策略(BPF 版 SELinux)</td></tr></tbody></table><p>tracepoint 和 kprobe 的取舍要单独说,因为天天遇到:</p><table tabindex="0"><thead><tr><th></th><th>tracepoint</th><th>kprobe</th></tr></thead><tbody><tr><td>稳定性</td><td><strong>内核 ABI 承诺,跨版本稳定</strong></td><td>挂的是内核函数,改名/改参数就失效</td></tr><tr><td>覆盖面</td><td>只有预埋的点</td><td>几乎任意内核函数</td></tr><tr><td>字段</td><td>明确、文档化</td><td>要自己看内核源码对参数</td></tr></tbody></table><p>原则:<strong>tracepoint 够用就用 tracepoint,不够再 kprobe</strong>——前者是官方承诺的接口,后者是&quot;在别人家房梁上钉钉子&quot;,内核一升级你的脚本可能就哑了。</p><hr><h2 id="四、bpftrace-十分钟上手的入口" tabindex="-1">四、bpftrace:十分钟上手的入口 <a class="header-anchor" href="#四、bpftrace-十分钟上手的入口" aria-label="Permalink to &quot;四、bpftrace:十分钟上手的入口&quot;">​</a></h2><p>eBPF 原生开发(写 C、管加载、读 map)门槛不低,bpftrace 把它压缩成 awk 风格的单行脚本——<strong>排障现场的第一武器</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 这台机器上谁在疯狂调 syscall?(全机 syscall 排行)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bpftrace</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;tracepoint:syscalls:sys_enter_* { @[comm] = count(); }&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 哪个进程在反复打开什么文件?(配置被谁动了的破案神器)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bpftrace</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;tracepoint:syscalls:sys_enter_openat</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">             { printf(&quot;%s %s\\n&quot;, comm, str(args-&gt;filename)); }&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># vfs_read 延迟直方图:慢是整体慢,还是长尾慢?</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bpftrace</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">kprobe:vfs_read { @start[tid] = nsecs; }</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">kretprobe:vfs_read /@start[tid]/ {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  @lat = hist((nsecs - @start[tid]) / 1000);</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  delete(@start[tid]);</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}&#39;</span></span></code></pre></div><p>第三个脚本的模式(入口记时间戳、返回算差值、聚成直方图)是 eBPF 观测的万能模板,<strong>任何&quot;XX 耗时分布&quot;问题都套它</strong>。输出的直方图能直接回答 26 篇剧本里那个关键问题:p99 抖动到底是普遍变慢,还是 1% 的长尾——两者的根因方向完全不同。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bpftrace</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;tracepoint:syscalls:*&#39;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 列出可用 hook 点,现场翻字典</span></span></code></pre></div><p>bpftrace 的定位:<strong>快速排查、一次性脚本、验证猜想</strong>。要写常驻的观测程序,看下一节。</p><hr><h2 id="五、bcc-与-libbpf-co-re-从脚本到产品" tabindex="-1">五、BCC 与 libbpf + CO-RE:从脚本到产品 <a class="header-anchor" href="#五、bcc-与-libbpf-co-re-从脚本到产品" aria-label="Permalink to &quot;五、BCC 与 libbpf + CO-RE:从脚本到产品&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>BCC</th><th>libbpf + CO-RE</th></tr></thead><tbody><tr><td>形态</td><td>Python 前端,内嵌 C 写 BPF</td><td>纯编译型,C/Rust/Go</td></tr><tr><td>编译时机</td><td><strong>运行时现场编译</strong>(每次启动)</td><td>编译一次,到处运行</td></tr><tr><td>依赖</td><td>拖着整个 clang/LLVM,很重</td><td>一个小二进制</td></tr><tr><td>适合</td><td>学习、用现成工具</td><td><strong>生产级常驻程序的标准答案</strong></td></tr></tbody></table><p>CO-RE(Compile Once, Run Everywhere)解决的是 eBPF 落地最大的痛点:不同内核版本的内部结构体布局不一样,以前的 BPF 程序要在目标机器上现场编译才能对上偏移。CO-RE 借助内核自带的 BTF(类型信息),<strong>在加载时自动重定位字段偏移</strong>——编译一次的二进制,扔到不同版本的内核上都能跑。现代生产级 eBPF 项目(Cilium、Pixie……)全是这条路线。</p><p>BCC 生态里那批现成工具不用写一行代码,直接对症下药:</p><table tabindex="0"><thead><tr><th>症状</th><th>工具</th><th>回答什么</th></tr></thead><tbody><tr><td>机器上有奇怪的短命进程</td><td><code>execsnoop</code></td><td>谁在 exec 什么命令(抓挖矿脚本名场面)</td></tr><tr><td>配置文件被谁改了/读了</td><td><code>opensnoop</code></td><td>全机每一次 open</td></tr><tr><td>谁在对外建连</td><td><code>tcpconnect</code> / <code>tcptop</code></td><td>每条出站连接 + 流量排行</td></tr><tr><td>磁盘延迟可疑</td><td><code>biolatency</code></td><td>块设备 IO 延迟直方图</td></tr><tr><td>CPU 没满但就是慢</td><td><code>runqlat</code></td><td><strong>就绪后等 CPU 等了多久</strong>(调度延迟)</td></tr><tr><td>想要全机火焰图</td><td><code>profile</code></td><td>内核 + 用户态混合采样</td></tr></tbody></table><p><code>runqlat</code> 值得划重点:它量化的&quot;任务就绪了却排队等 CPU&quot;的时间,正是 26 篇说的传统工具盲区——CPU 利用率没满、应用没报错,延迟却凭空多出来,answer 往往在这。</p><hr><h2 id="六、网络主战场-xdp-和-tc" tabindex="-1">六、网络主战场:XDP 和 TC <a class="header-anchor" href="#六、网络主战场-xdp-和-tc" aria-label="Permalink to &quot;六、网络主战场:XDP 和 TC&quot;">​</a></h2><p>观测之外,eBPF 的第二战场是直接<strong>处理</strong>网络包。XDP(eXpress Data Path)挂在网卡驱动收包的最早一刻——<strong>比内核协议栈还早,sk_buff 都还没分配</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>网卡收到包</span></span>
<span class="line"><span>  → XDP 程序先看一眼,裁决:</span></span>
<span class="line"><span>      DROP      → 当场丢弃(一个 sk_buff 都不用建,丢包成本趋近于零)</span></span>
<span class="line"><span>      PASS      → 放行,走正常协议栈</span></span>
<span class="line"><span>      TX        → 原网卡弹回去(改包转发)</span></span>
<span class="line"><span>      REDIRECT  → 转给其它网卡 / CPU / AF_XDP socket</span></span>
<span class="line"><span>  → 内核协议栈(只有 PASS 的包才走到这)</span></span></code></pre></div><p>为什么 DDoS 防御非它不可:攻击流量打过来,iptables 丢包要等包走完协议栈前半程,<strong>XDP 在门口就把包拍死</strong>,单机抗千万 pps 级的攻击流量。负载均衡同理——Facebook 的 Katran、Cloudflare 的边缘清洗,都是 XDP 写的。</p><p>TC(traffic control)层的 hook 在协议栈更深处,慢一点但<strong>能拿到完整的 skb 上下文</strong>(知道包属于哪个 socket、哪个 cgroup),适合做策略:容器间网络规则、限速、服务网格数据面。</p><p>最大的现实案例是 <strong>Cilium</strong>:K8s 网络插件,用 eBPF 全面替换 kube-proxy 的 iptables 方案。iptables 是链式规则,service 一多就是 O(n) 线性匹配,几千个 service 时每个包都要过长队;eBPF 用 map 做 O(1) 查找,顺手把网络策略、负载均衡、可观测性全包了——<strong>这是&quot;eBPF 重写 Linux 网络基础设施&quot;的代表作</strong>(K8s 网络详见 backendLearning 系列)。</p><hr><h2 id="七、可观测性的几个名场面" tabindex="-1">七、可观测性的几个名场面 <a class="header-anchor" href="#七、可观测性的几个名场面" aria-label="Permalink to &quot;七、可观测性的几个名场面&quot;">​</a></h2><p>把工具对回真实问题,这几个场景值得记:</p><ul><li><strong>&quot;CPU 不忙但延迟高&quot;</strong> → <code>runqlat</code>:调度延迟直方图,确认是不是就绪队列在排队(容器里叠加 25 篇的 throttle 检查)。</li><li><strong>&quot;磁盘平均指标正常,应用偶发慢&quot;</strong> → <code>biolatency</code>:平均值看不出的 IO 长尾,直方图一目了然——99% 的 IO 在 1ms 内,1% 在 100ms,这 1% 就是你的 p99。</li><li><strong>&quot;网络偶发超时&quot;</strong> → 跟踪 <code>tcp_retransmit_skb</code>(现成工具 <code>tcpretrans</code>):每次重传打出四元组,瞬间知道是哪条链路在丢包。</li><li><strong>&quot;锁竞争,但 perf 看不到&quot;</strong> → CPU 采样只能看到&quot;在烧 CPU 的代码&quot;,<strong>等锁的线程不烧 CPU</strong>,在 perf 火焰图上隐形。这时看 off-CPU 时间(线程不在 CPU 上的时间花在等什么)+ futex 跟踪,正好补上 on-CPU 分析的盲区。</li></ul><p>规律:<strong>perf 负责&quot;CPU 在干什么&quot;,eBPF 负责&quot;时间去哪了&quot;</strong>——后者覆盖等待、排队、长尾这些采样看不见的暗物质。</p><hr><h2 id="八、边界与风险-它不是免费的" tabindex="-1">八、边界与风险:它不是免费的 <a class="header-anchor" href="#八、边界与风险-它不是免费的" aria-label="Permalink to &quot;八、边界与风险:它不是免费的&quot;">​</a></h2><p>eBPF 强,但每一条边界都要心里有数:</p><ol><li><strong>内核版本差异</strong>——能力随内核演进(4.x 基础、5.x 才有 ring buffer / 有界循环 / CO-RE 成熟),老内核很多玩法直接没有。</li><li><strong>verifier 限制</strong>——栈 512 字节、循环有界、指令数受限,复杂逻辑要拆,有时被 verifier 拒得莫名其妙(报错信息堪称天书)。</li><li><strong>观测本身有开销</strong>——hook 一个每秒百万次的事件、还在里面 printf,系统直接被你拖垮。<strong>高频事件只做内核内聚合(count/hist),永远不要逐条输出</strong>。</li><li><strong>kprobe 字段不稳定</strong>——内核升级,函数改名、参数变化,脚本静默失效。生产长期跑的程序尽量 tracepoint + CO-RE。</li><li><strong>权限要求高</strong>——通常要 root 或 CAP_BPF / CAP_SYS_ADMIN,这本身就是一个安全敏感面(能挂 uprobe 就能读 TLS 明文)。</li><li><strong>容器/云环境受限</strong>——托管 K8s、安全策略可能禁用部分 BPF 能力,本地能跑的脚本线上不一定能。</li></ol><p>使用原则浓缩成一张 checklist:<strong>优先 tracepoint 再 kprobe;高频事件只聚合;先在测试环境跑;加 pid/comm/cgroup 过滤;观测窗口短而明确;长期程序用 libbpf + CO-RE</strong>。</p><p>最后摆正位置:eBPF <strong>不替代</strong>应用日志、指标系统、分布式 tracing、语言级 profiler,更不替代容量规划——那些回答&quot;应用在干什么&quot;,eBPF 回答的是**&quot;应用看不见的内核层发生了什么&quot;**。它是补盲区的,不是推倒重来的。</p><hr><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><ol><li><strong>把 eBPF 当&quot;高级 strace&quot;随便挂</strong>——挂错 hook 一样能拖垮系统:高频 kprobe + 逐条 printf 的组合,开销不比 strace 小。聚合,永远先聚合。</li><li><strong>新手直挂 kprobe</strong>——内核一升级函数没了,脚本静默失效还以为&quot;没问题&quot;。有 tracepoint 用 tracepoint。</li><li><strong>在生产首跑没验证过的脚本</strong>——verifier 保证不崩内核,<strong>不保证不拖慢内核</strong>。先测试环境,先短窗口。</li><li><strong>忘了加过滤条件</strong>——不带 pid/cgroup 过滤的全机跟踪,事件量可能比你预想的大几个数量级。</li><li><strong>用 perf 火焰图找等锁问题</strong>——等待不烧 CPU,on-CPU 采样看不见,要 off-CPU 分析 / futex 跟踪。</li><li><strong>以为本地能跑 = 线上能跑</strong>——内核版本、BTF 有无、容器安全策略,三道坎每道都可能拦住你。</li><li><strong>拿 eBPF 替代日志和指标</strong>——它是内核层的补盲工具,应用层的可观测性基建一样都不能少。</li><li><strong>写复杂业务逻辑硬怼 verifier</strong>——512 字节栈和有界循环是硬墙,复杂逻辑放用户态,内核里只做采集和聚合。</li></ol><hr><p>下一篇:<code>28-OS在云原生时代.md</code>,全系列最后一篇——把 28 篇串成一张完整的心智图:<strong>K8s、Service Mesh、Serverless 这些时髦词底下全是 OS 的老问题</strong>,Linux 内核自己正往哪走(io_uring / eBPF / cgroup v2 / Rust),以及学完这个系列之后,往下还能怎么深。</p>`,60)])])}const b=s(p,[["render",r]]);export{g as __pageData,b as default};
